SELECT exam_date, COUNT(*) AS total_exams
FROM exams
GROUP BY exam_date;

SELECT exam_code, exam_date, session, subject_code, branch_code, duration
FROM exams
WHERE subject_code = 'Biology' AND branch_code = 77692;

SELECT s.student_name, b.branch_name
FROM students s
JOIN branches b ON s.branch_id = b.branch_id;
